{
  double qxd;
  // int8_t maxlev;
  qxd = floor(x / D);

  // maxlev = 1<<(B-1);

  // printf("x=%f,qxd=%f,maxlev=%d\n",x,qxd, maxlev);

  if (qxd <= -128)
    qxd = -128;
  else if (qxd >= 128)
    qxd = 127;

